var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"벌써 휴가도 마지막 날이네.","JPN":"もうこの旅も最終日か。","ENG":"It's already the last day of our vacation.","TWN":"好快喔，今天已經是假期最後一天。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"아쉽다……. 시간이 금방 지나갔어.","JPN":"さみしいな……時間があっという間に過ぎちゃった。","ENG":"Aw… Time sure flies when you're having fun.","TWN":"真捨不得……時間怎麼過這麼快～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"마지막 날이니 오늘 밤은 더 원없이 즐겨.","JPN":"最終日だから今夜は好きなだけ楽しんでいいよ。","ENG":"Indulge yourself tonight, since this is the last day.","TWN":"既然是最後一天，那我們更要盡情享受最後一晚。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래야 자기랑 같이 온 나도 만족할 수 있으니까.","JPN":"ハニーの喜ぶ姿が僕にとって一番の幸せだから。","ENG":"Nothing would satisfy more than you really enjoying yourself here.","TWN":"這樣才不枉費和親愛的一起來玩。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기 일은 좀 어때? 계속 통화하는 것 같던데, 잘 해결됐어?","JPN":"ダーリンの仕事はどう？　ずっと通話していたけど、ちゃんと解決できたの？","ENG":"How's your work going, babe? You seem to be on the phone a lot… Did everything work out?","TWN":"親愛的事呢？我看你好像一直在講電話，事情還順利嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"아, 그럼. 물론이지. 도시 관리국에 있는 지인한테 부탁했으니까.","JPN":"ああ、もちろん。都市管理局の知り合いに頼んでおいたからね。","ENG":"Oh, yes. Of course. I called in a favor with someone at the City Managements.","TWN":"喔～那當然，我有拜託城市管理局的好朋友處理。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"도시 관리국에? 어떤 사람이야? 혹시 나도 알 만큼 높은 사람?","JPN":"都市管理局に？　どんな人？　私も知っているぐらい偉い人？","ENG":"The City Managements? Who is it? Someone famous enough for me to recognize?","TWN":"城市管理局嗎？誰啊？是我也認識的人嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그렇게 대단한 사람은 아니고 말이 좀 통할 뿐이야. 사업하다가 알게 됐거든.","JPN":"そこまでお偉いさんではないけど、まあまあ話が通じる人さ。仕事で知り合ったんだ。","ENG":"No, it's not a big shot like that. We just click well. A former business associate.","TWN":"不是什麼大人物啦，只是個聊得來的朋友，是做生意的時候認識的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"굉장하다…… 난 스튜어디스 일 할 때도 그런 사람들 못 만나 봤는데.","JPN":"すごい……私はCA時代でさえそんな凄い人に会ったことないのに。","ENG":"That's amazing… I never got to see anyone that important, even when I was working as a flight attendant.","TWN":"好厲害喔……我在飛機上服務客人時，也沒見過那種大人物呢～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"신경 쓰지 마. 앞으로는 질리도록 만나게 될 테니까.","JPN":"気にするな。これからは飽きるほど会うことになるからさ。","ENG":"Don't let that bother you. You'll be mingling with no one but big shots from now on.","TWN":"沒什麼啦，以後見面次數可能會多到很煩呢。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그래, 어디 보자. 관리국이라면 돈만 빨아먹는 타격조 놈들보다는 잘 처리했겠지.","JPN":"さてと、どれどれ。管理局なら金だけ吸い取る突撃隊よりはうまく対応してくれただろうな。","ENG":"Let's see… I'm sure the Administration would have done a better job than those money-sucking strike squads.","TWN":"我來看看～ 管理局應該會處理得比那些視錢如命的打擊組好吧？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"지금쯤이면 붙잡혀서 슈퍼맥스급 교도소로 갔거나, 기계인 게 탄로나서……","JPN":"今頃連行されてスーパーマックス級の刑務所に送られたか、機械ってことがバレて……","ENG":"By now, she's probably locked up in a supermax prison or exposed as a machine…","TWN":"現在要嘛被抓去監獄關，要嘛機器人的身分曝光……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자기야, 저기 봐!","JPN":"ダーリン、あれを見て！","ENG":"Babe, look!","TWN":"親愛的，你看那邊！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"하하, 그렇게 갑자기 안기면 놀란다니까.","JPN":"ハハ、そんな急に抱きついて来たらビックリするだろ。","ENG":"Haha, I told you I get jumpy if you hug me so suddenly.","TWN":"哈哈，你突然這樣抱住我，嚇我一跳呢～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그런데 왜 그래? 하늘에 뭐가 있는데?","JPN":"どうしたんだ？　空に何かあるのかい？","ENG":"Anyway, what is it? Is there something up in the sky?","TWN":"是怎麼了嗎？ 空中有什麼嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"비행기야! 저기 연기 보여?","JPN":"飛行機よ！　あの煙、すご～い！","ENG":"It's a plane! See that smoke?","TWN":"飛機欸！你有看到白煙嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"이 호텔은 밤에 에어쇼도 해 주나 봐. 마지막 날까지 정말 최고야…….","JPN":"このホテルは夜にエアショーもやるのね。旅の最終日まで本当に最高！","ENG":"This hotel must put on airshows too. Even at night! It's perfect to the very last day…","TWN":"這個飯店晚上還有飛行表演呢，真是完美的最後一夜……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"잠깐만, 저 연기는 일부러 피워 올리는 게 아닌 것 같은데……?","JPN":"待って、あの煙はわざわざショーのために作ったものじゃないような……？","ENG":"Hang on… That smoke doesn't look like it's for show…","TWN":"等等，那個白煙似乎不是刻意的……？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"어, 어어어어? 추락한다!","JPN":"えっ？　墜落してるぞ！","ENG":"Huh? Woah... Woah, woah, woah! It's going to crash!","TWN":"喔喔喔喔？墜機了！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"세상에! 사람이 타고 있는 거 아냐?","JPN":"危ない！　人が乗っているんじゃないの！？","ENG":"Oh my gosh! Are there people on that thing?","TWN":"天啊！裡面有人嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"어, 어떡해. 에어쇼가 아니었나 봐…….","JPN":"ど、どうしよう。エアショーじゃなかったみたい……","ENG":"Oh no… It wasn't an airshow…","TWN":"怎…怎麼辦？好像不是飛行表演……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"쳇. 마지막 밤을 저런 꼴사나운 사고로 장식하다니…….","JPN":"ちっ、せっかくの旅の最後にあんなみっともない事故を見ることになるとは……","ENG":"Hmph. She just had to spoil my last night here with such a messy accident…","TWN":"嗟！竟然搞砸我的最後一夜……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어머, 대표님이잖아. 안 그래도 막 연락하려던 참이었는데 잘됐네.","JPN":"あら、代表じゃない。ちょうど今連絡しようとしたところよ、よかったわ。","ENG":"Oh, hey boss. I was actually right about to call you.","TWN":"喔！這不是代表嗎？我正想打給你呢！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"어떻게 된 거지, 셰나? 내가 묵는 동안 신경 거슬릴 일 없게 알아서 처리하라고 하지 않았나?","JPN":"どういうことだ、シェナ？　休み中は目障りなことが起きないようにと頼んだはずだが。","ENG":"What the hell happened, Shena? Didn't I tell you to make sure nothing bothered me during my stay here?","TWN":"世娜，這是怎麼回事？我不是說我休假期間，你自己把事情處理好不要煩我嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"응? 갑자기 무슨 소리야?","JPN":"なに？　急にどうしたの？","ENG":"Huh? What are you talking about?","TWN":"嗯？這是什麼意思？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"비행기가 추락했단 말이다! 그것도 호텔 바로 코앞에서!","JPN":"飛行機が墜落したんだ！　しかもホテルの目の前に！","ENG":"A plane crashed! Right in front of our hotel!","TWN":"發生墜機事件！而且還是在飯店這邊！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어…… 정말?","JPN":"え……ほんと……？","ENG":"Woah… Really?","TWN":"哇……真的假的？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그럼 빨리 거기서 피하는 게 좋을걸, 대표님.","JPN":"なら今すぐそこから離れたほうがいいわ、代表。","ENG":"Then I suggest you get away from there ASAP, boss.","TWN":"那代表你趕快找個地方躲好吧！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그거, 아마 경호팀이 격추하려다 실패…….","JPN":"それって、多分警護室が撃墜に失敗……","ENG":"That's probably the plane we tried to shoot down before-","TWN":"可能是警衛隊擊落失敗……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"닥쳐! 하여튼 한 놈도 일을 믿고 맡길 수가 없군!","JPN":"もういい！　まったく、どいつもこいつも安心して任せられないな！","ENG":"Shut up! Can I count on anyone to do their damn job?!","TWN":"閉嘴！總之你們沒有一個傢伙是信得過的！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"당장 저 비행기 주인이 누군지 찾아와! 내 휴가를 망친 대가를 톡톡히 치르게 해 주겠어!","JPN":"今すぐあの飛行機の持ち主を探せ！　せっかくの休みを台無しにした代償を払ってもらう！","ENG":"Go find out whose plane that is right now! I'll make them pay for ruining my vacation!","TWN":"馬上找出那架飛機的主人是誰！竟然毀掉我的假期，我要讓他付出代價！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_QM","text":{"KOREA":"일단은 제가 탈취한 것이긴 합니다만.","JPN":"一応、私が奪取したものではありますが。","ENG":"Well, I must confess: I'm the one who hijacked it.","TWN":"是我劫走飛機的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"어……? 어어? 어……?","JPN":"え……？　ええ？　えっ……？","ENG":"Huh…? Huh? Huh…?","TWN":"嗯……？喂喂？……？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"여보세요? 대표님? 대표니임?","JPN":"もしもし？　代表？　聞こえます？","ENG":"Hello? Boss? You still with me?","TWN":"喂？代表？代表你還在嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"연체된 이자부터 순서대로 청산해야 하지 않겠습니까.","JPN":"延滞した利子から順に清算するべきだと思いますが。","ENG":"It's time we settled your deferred interest payment in due sequence.","TWN":"是不是該從滯納利息開始，一筆一筆地算清楚呢？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"호, 호라이즌……? 정말 너라고……?","JPN":"ホ、ホライズン……？　本当に貴様か……？","ENG":"H-Horizon…? Is that really you…?","TWN":"地…地平線……？真的是你……？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇습니다. 접니다.","JPN":"はい、私です。","ENG":"Yes. It's me.","TWN":"是的。是我。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"네가, 네가 여길 어떻게 알고……!","JPN":"き、貴様がどうやってここに……？","ENG":"H-how did you know I'd be here…?!","TWN":"你…你怎麼會知道我在這裡……！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"네. 당신이 제 예상 이상으로 종적을 잘 감춰서 무척 놀랐습니다.","JPN":"はい。あなたが私の予想以上にうまく行方をくらましたので、とても驚きました。","ENG":"Indeed. I was most impressed you managed to hide so well.","TWN":"我非常驚訝，沒想到你比我想像的還會躲。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이렇게 올 수 있었던 것은 유능한 협력업체의 조력 덕분이라고 해 두죠.","JPN":"こうして来られたのは有能な協力会社のおかげだと言っておきましょう。","ENG":"Let's just say I've had the privilege of enjoying the assistance of a very capable partner firm.","TWN":"我之所以會找到這裡，都要感謝夠給力的合作公司。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"그럴 리가 없어…… 나에 대한 정보는 상부에서 모조리 없앴을 텐데……!","JPN":"そんなはずがない……僕に関する情報は上がすべて消してくれたはず……","ENG":"But that's impossible… They're supposed to have scrubbed all information about me…","TWN":"這怎麼可能……上面應該將有關我的資訊都清除啦……！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"자, 자기야, 왜 그래? 저 이상한 애랑 아는 사이야?","JPN":"ダ、ダーリン、どうしたの？　あの変な子と知り合いなの？","ENG":"B-babe? What's wrong? Do you know this strange girl?","TWN":"親…親愛的，怎麼了？你認識那個奇怪的人嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……호라이즌 파이낸스 최장기 채무자. 윌버 웨이틀리.","JPN":"……ホライズン・ファイナンス最長期債務者、ウィルバー・ウェイトリー。","ENG":"…No one else has remained in debt to Horizon Finance so long, Wilbur Whateley.","TWN":"地平線金融歷史最悠久的債務人，韋爾伯·韋特利。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"현 시간부로 중단 중이던 추심을 재개합니다.","JPN":"現時刻をもって、中断していた取り立てを再開します。","ENG":"As of this moment, Horizon Finance will resume your debt recovery.","TWN":"之前沒還完的債務，現在重新向你追討。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"}]`);export{e as default};